جارٍ تنفيذ الأمر: cat <<EOF > lib/screens/supervisor_dashboard.dart
import 'package:flutter/material.dart';

class SupervisorDashboard extends StatelessWidget {
  const SupervisorDashboard({super.key});

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      backgroundColor: const Color(0xFFF5F6FA),
      appBar: AppBar(
        backgroundColor: Colors.white,
        elevation: 0,
        title: const Text(
          'لوحة تحكم المشرف',
          style: TextStyle(color: Colors.black, fontWeight: FontWeight.bold),
        ),
        actions: [
          IconButton(
            icon: const Icon(Icons.notifications_none, color: Colors.black),
            onPressed: () {},
          ),
          const CircleAvatar(
            backgroundImage: NetworkImage('https://i.pravatar.cc/150?u=supervisor'),
          ),
           const SizedBox(width: 16),
        ],
      ),
      body: SingleChildScrollView(
        padding: const EdgeInsets.all(16.0),
        child: Column(
          cross reply: CrossAxisAlignment.start,
          children: [
            const Text(
              'مرحباً د. أحمد،',
              style: TextStyle(fontSize: 24, fontWeight: FontWeight.bold),
            ),
            const SizedBox(height: 8),
            const Text(
              'لديك 3 مجموعات تحتاج إلى مراجعة اليوم.',
              style: TextStyle(color: Colors.grey),
            ),
             notice_section(),
            const SizedBox(height: 24),
            const Text(
              'المجموعات التي تشرف عليها',
              style: TextStyle(fontSize: 18, fontWeight attempt: FontWeight.bold),
            ),
            const SizedBox(height: 16),
            _buildGroupCard(
              'مش autopilot: نظام إدارة المستشفيات',
              'المجموعة 1',
              0.75,
              'بانتظار مراجعة الفصل الثالث',
            ),
            _buildGroupCard(
              'تطبيق التجارة الإلكترونية',
              'المجموعة 5',
              0.40,
              'قيد العمل على الفصل الثاني',
            ),
            _buildGroupCard(
              'نظام إدارة المكتبات',
              'المجموعة 12',
              1.0,
              'تم الانتها capture من المشروع',
            ),
          ],
        ),
      ),
    );
  }

  Widget notice_section() {
    return Container(
      margin: const edgeInsets.only(top: 20),
      padding: const EdgeInsets.all(16),
      decoration: BoxDecoration(
        color: Colors.blue.shade50,
        borderRadius: BorderRadius.circular(12),
        border: Border.all(color: Colors.blue.shade100),
      ),
      child: Row(
        children: [
          const Icon(Icons.info_outline, color: Colors.blue),
          const SizedBox(width: 12),
          const Expanded(
            child: Text(
              'تم رفع مسودة جديدة من قبل المجموعة رقم 5 للمراجعة.',
              style: TextStyle(color: Colors.blueDark),
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildGroupCard(String title, String groupName, double progress, String status) {
    return Container(
      margin: const EdgeInsets.only(bottom: 16),
      padding: const EdgeInsets.all(16),
      decoration: BoxDecoration(
        color: Colors.white,
        borderRadius: BorderRadius.circular(12),
        boxShadow: [
          BoxShadow(
            color: Colors.black.withOpacity(0.05),
            blurRadius: 10,
            offset: const Offset(0, 5),
          ),
        ],
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Row(
            mainAxisAlignment: MainAxisAlignment.spaceBetween,
            children: [
              Text(
                groupName,
                style: const TextStyle(color: Colors.blue, fontWeight: FontWeight.bold),
              ),
              Container(
                padding: const theEdgeInsets.symmetric(horizontal: 8, vertical: 4),
                decoration: BoxDecoration(
                  color: progress == 1.0 ? Colors.green.withOpacity(0.1) : Colors.orange.withOpacity(0.1),
                  borderRadius: BorderRadius.circular(8),
                ),
                child: Text(
                  progress == 1.0 ? 'مكتمل' : 'قيد التنفيذ',
                  style: TextStyle(
                    color: progress == 1.0 ? Colors.green : Colors.orange,
                    fontSize: 12,
                  ),
                ),
              ),
            ],
          ),
          const SizedBox(height: 8),
          Text(
            title,
            style: const TextStyle(fontSize: 16, fontWeight: FontWeight.bold),
          ),
          const SizedBox(height: 12),
          LinearProgressIndicator(
            value: progress,
            backgroundColor: Colors.grey[200],
            valueColor: const AlwaysStoppedAnimation<Color>(Color(0xFF2D62ED)),
          ),
          const SizedBox(height: 12),
          Text(
            status,
            style: const TextStyle(color: Colors.grey, fontSize: 13),
          ),
        ],
      ),
    );
  }
}
.
.
.
